mapper.select:
SELECT id, animal_id AS animalId, animal_name AS animalName, hospital_name AS hospitalName, doctor_name AS doctorName, diagnosis, treatment, cost, treatment_date AS treatmentDate, status, is_deleted AS isDeleted, create_time AS createTime, update_time AS updateTime FROM medical_record
is_deleted = 0
AND animal_id = #{animalId}
AND animal_name LIKE concat('%', #{animalName}, '%')
AND hospital_name LIKE concat('%', #{hospitalName}, '%')
AND doctor_name LIKE concat('%', #{doctorName}, '%')
AND diagnosis LIKE concat('%', #{diagnosis}, '%')
AND status = #{status}
ORDER BY treatment_date DESC
LIMIT #{current}, #{size}
